#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int *A = (int*)malloc(N*sizeof(int));
        int maxA = 0;
        for(int i=0;i<N;i++){
            scanf("%d", &A[i]);
            if(A[i]>maxA) maxA = A[i];
        }
        // visited array up to 100000 (constraint)
        static bool visited[100001];
        memset(visited, 0, sizeof(visited));
        for(int i=0;i<N;i++){
            int val;
            if(!visited[A[i]]){
                val = A[i];
                visited[A[i]] = true;
            }else{
                val = maxA;
            }
            printf("%d", val);
            if(i+1<N) printf(" ");
        }
        printf("\n");
        free(A);
    }
    return 0;
}

