    while(T--){
        int N; cin>>N;
        vector<int> A(N);
        int maxA=0;
        for(int i=0;i<N;i++){
            cin>>A[i];
            maxA = max(maxA, A[i]);
        }
        unordered_set<int> placed;
        placed.reserve(N*2);
        for(int i=0;i<N;i++){
            int out;
            if(placed.find(A[i])==placed.end()){
                out = A[i];
                placed.insert(A[i]);
            }else{
                out = maxA;
            }
            cout<<out<<(i+1==N?'\n':' ');
        }
    }
    return 0;
}

