const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = input[idx++];
let outputs = [];
for (let t = 0; t < T; t++) {
  const N = input[idx++];
  const A = input.slice(idx, idx + N);
  idx += N;
  let maxA = 0;
  for (const v of A) if (v > maxA) maxA = v;
  const placed = new Set();
  const B = [];
  for (const v of A) {
    if (!placed.has(v)) {
      B.push(v);
      placed.add(v);
    } else {
      B.push(maxA);
    }
  }
  outputs.push(B.join(' '));
}
console.log(outputs.join('\n'));

